-- Workflow audit trail indexes for state transition queries
CREATE INDEX IF NOT EXISTS idx_workflow_audit_claim_state_time 
ON workflow_audit_trail(claim_id, new_state, created_at);

CREATE INDEX IF NOT EXISTS idx_workflow_audit_override 
ON workflow_audit_trail(executive_override, created_at);

-- Claim involvement tracking index for segregation analysis
CREATE INDEX IF NOT EXISTS idx_involvement_claim_user_stage 
ON claim_involvement_tracking(claim_id, user_id, workflow_stage);

-- Role assignment audit indexes for role change analytics
CREATE INDEX IF NOT EXISTS idx_role_audit_user_time 
ON role_assignment_audit(user_id, timestamp);

CREATE INDEX IF NOT EXISTS idx_role_audit_tenant_time 
ON role_assignment_audit(tenant_id, timestamp);

